[
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "critical",
    "description": "Out-of-bounds read in cookie_tailmatch() function. When hostname_len equals cookie_domain_len, the expression '*(hostname + hostname_len - cookie_domain_len - 1)' evaluates to '*(hostname - 1)', reading memory before the buffer. This occurs because the boundary check at line 129 only ensures hostname_len >= cookie_domain_len, not strictly greater than. An attacker can craft cookies with domains matching the entire hostname to trigger this read.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
+  if(hostname_len > cookie_domain_len && '.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 963,
    "severity": "critical",
    "description": "NULL pointer dereference in passwd_callback(). The function calls strlen() on global_passwd without first checking if it's NULL. If a NULL password is passed (e.g., for an encrypted certificate without a password callback), this will cause a crash. This is a denial of service vulnerability.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -959,6 +959,8 @@ static int passwd_callback(char *buf, int num, int encrypting,
 {
   DEBUGASSERT(0 == encrypting);

+  if(!global_passwd)
+    return 0;
   if(!encrypting) {
     int klen = curlx_uztosi(strlen((char *)global_passwd));
     if(num > klen) {
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2210,
    "severity": "high",
    "description": "Incorrect union member access in ossl_verifyhost(). The code unconditionally accesses 'check->d.ia5' for both GEN_DNS and GEN_IPADD certificate subject alternative names. However, the GENERAL_NAME union uses different members for different types: 'dNSName' (ASN1_IA5STRING) for DNS names and 'iPAddress' (ASN1_OCTET_STRING) for IP addresses. Accessing the wrong union member leads to type confusion and potential out-of-bounds reads of certificate data.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2207,8 +2207,14 @@
       /* only check alternatives of the same type the target is */
       if(check->type == target) {
         /* get data and length */
-        const char *altptr = (char *)ASN1_STRING_get0_data(check->d.ia5);
-        size_t altlen = (size_t) ASN1_STRING_length(check->d.ia5);
+        const char *altptr;
+        size_t altlen;
+        if(target == GEN_DNS) {
+          altptr = (char *)ASN1_STRING_get0_data(check->d.dNSName);
+          altlen = (size_t) ASN1_STRING_length(check->d.dNSName);
+        } else {
+          altptr = (char *)ASN1_STRING_get0_data(check->d.iPAddress);
+          altlen = (size_t) ASN1_STRING_length(check->d.iPAddress);
+        }

         switch(target) {
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2167,
    "severity": "high",
    "description": "Uninitialized variable use in ossl_verifyhost(). The 'addr' variable is declared uninitialized at line 2149/2151. If neither IPv6 nor IPv4 parsing succeeds (e.g., when target remains GEN_DNS), the addr structure is never initialized. Later, if the code path reaches the GEN_IPADD comparison at line 2237 while target is still GEN_IPADD but addr wasn't properly set, this leads to use of uninitialized memory. However, addrlen=0 check at line 2237 prevents this in practice; add explicit zero-initialization for safety.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2147,11 +2147,11 @@
   size_t addrlen = 0;
   STACK_OF(GENERAL_NAME) *altnames;
 #ifdef ENABLE_IPV6
-  struct in6_addr addr;
+  struct in6_addr addr = {0};
 #else
-  struct in_addr addr;
+  struct in_addr addr = {0};
 #endif
   CURLcode result = CURLE_OK;
   bool dNSName = FALSE; /* if a dNSName field exists in the cert */
   bool iPAddress = FALSE; /* if a iPAddress field exists in the cert */
"
  },
  {
    "file": "lib/base64.c",
    "line": 110,
    "severity": "medium",
    "description": "Potential signed integer underflow in rawlen calculation when numQuantums is 1 and padding is 2. The expression 'rawlen = (numQuantums * 3) - padding' could theoretically result in a value less than expected for edge cases. While the current validation (srclen % 4 == 0 and srclen >= 4) ensures numQuantums >= 1, the calculation doesn't account for invalid base64 sequences where padding > actual encoded data. Add explicit validation to ensure rawlen is positive.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -108,6 +108,9 @@
   /* Calculate the size of the decoded string */
   rawlen = (numQuantums * 3) - padding;

+  if((ssize_t)rawlen <= 0)
+    return CURLE_BAD_CONTENT_ENCODING;
+
   /* Allocate our buffer including room for a null-terminator */
   newstr = malloc(rawlen + 1);
   if(!newstr)
"
  }
]

